import React, { useCallback, useState, useRef, useEffect } from 'react';
import type { TabbarItem, TabbarSelectionChangeDetail, TabbarProps } from '../../types/tabbar';
import { useTabbarOverflow } from './useTabbarOverflow';
import { TabbarOverflowButton } from './TabbarOverflowButton';
import './Tabbar.css';

export type { TabbarItem, TabbarSelectionChangeDetail, TabbarProps };

const OVERFLOW_BUTTON_ID = '__overflow__';

export const Tabbar: React.FC<TabbarProps> = ({
  className,
  items,
  selectedTab: controlledSelectedTab,
  defaultSelectedTab,
  onTabSelect,
  enableOverflow = false,
  noUnderline = false,
  accessibleName,
}) => {
  const tabItems = items;
  const resolvedDefault = defaultSelectedTab ?? tabItems[0]?.id ?? '';
  const [internalSelectedTab, setInternalSelectedTab] = useState<string>(resolvedDefault);

  // Track focused item by ID — decoupled from array positions
  const [focusedId, setFocusedId] = useState<string>(tabItems[0]?.id ?? '');

  const tabListRef = useRef<HTMLDivElement>(null);
  const tabRefs = useRef<Map<string, HTMLButtonElement>>(new Map());
  const overflowButtonRef = useRef<HTMLButtonElement>(null);

  const selectedTab = controlledSelectedTab ?? internalSelectedTab;

  const { visibleTabIds, overflowTabIds, hasOverflow, isReady } = useTabbarOverflow({
    enabled: enableOverflow,
    tabs: tabItems.map(t => ({ id: t.id, label: t.label })),
    selectedTabId: selectedTab,
    tabListRef,
  });

  const visibleTabs = enableOverflow && isReady
    ? tabItems.filter(t => visibleTabIds.includes(t.id))
    : [...tabItems];

  // Clamp focusedId when visibleTabs changes — if focused tab moved to overflow, reset to first visible
  useEffect(() => {
    if (focusedId === OVERFLOW_BUTTON_ID) return;
    const stillVisible = visibleTabs.some(t => t.id === focusedId);
    if (!stillVisible) {
      setFocusedId(visibleTabs[0]?.id ?? tabItems[0]?.id ?? '');
    }
  }, [visibleTabs.map(t => t.id).join(',')]);

  const handleTabSelect = useCallback(
    (tab: string) => {
      const previousTab = selectedTab;
      if (controlledSelectedTab === undefined) {
        setInternalSelectedTab(tab);
      }
      if (onTabSelect) {
        onTabSelect({ selectedTab: tab, previousTab });
      }
    },
    [selectedTab, controlledSelectedTab, onTabSelect]
  );

  const focusById = useCallback((id: string) => {
    setFocusedId(id);
    if (id === OVERFLOW_BUTTON_ID) {
      overflowButtonRef.current?.focus();
    } else {
      tabRefs.current.get(id)?.focus();
    }
  }, []);

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    const items: string[] = [
      ...visibleTabs.map(t => t.id),
      ...(hasOverflow ? [OVERFLOW_BUTTON_ID] : []),
    ];

    // Derive current focused item from DOM to avoid stale state
    const activeId = (() => {
      const active = document.activeElement;
      if (!active) return focusedId;
      const tabId = (active as HTMLElement).dataset.tabId;
      if (tabId && items.includes(tabId)) return tabId;
      if (overflowButtonRef.current === active) return OVERFLOW_BUTTON_ID;
      return focusedId;
    })();

    const currentIndex = items.indexOf(activeId);
    if (currentIndex === -1) return;

    const isRTL = document.documentElement.dir === "rtl";

    switch (e.key) {
      case 'ArrowRight': {
        e.preventDefault();
        e.stopPropagation();
        const nextIndex = currentIndex + (isRTL ? -1 : 1);
        if (nextIndex >= 0 && nextIndex < items.length) focusById(items[nextIndex]);
        break;
      }
      case 'ArrowLeft': {
        e.preventDefault();
        e.stopPropagation();
        const nextIndex = currentIndex + (isRTL ? 1 : -1);
        if (nextIndex >= 0 && nextIndex < items.length) focusById(items[nextIndex]);
        break;
      }
      case 'Home': {
        e.preventDefault();
        e.stopPropagation();
        focusById(items[0]);
        break;
      }
      case 'End': {
        e.preventDefault();
        e.stopPropagation();
        focusById(items[items.length - 1]);
        break;
      }
      case 'Enter': {
        if (activeId === OVERFLOW_BUTTON_ID) break; // let native button handle it
        e.preventDefault();
        handleTabSelect(activeId);
        break;
      }
      case ' ': {
        if (activeId === OVERFLOW_BUTTON_ID) break; // let native button handle it
        // Prevent page scroll; activation fires on keyUp
        e.preventDefault();
        break;
      }
    }
  }, [focusedId, visibleTabs, hasOverflow, focusById, handleTabSelect]);

  const handleKeyUp = useCallback((e: React.KeyboardEvent) => {
    if (e.key === ' ') {
      const items: string[] = [
        ...visibleTabs.map(t => t.id),
        ...(hasOverflow ? [OVERFLOW_BUTTON_ID] : []),
      ];
      const active = document.activeElement;
      const activeId = (() => {
        if (!active) return focusedId;
        const tabId = (active as HTMLElement).dataset.tabId;
        if (tabId && items.includes(tabId)) return tabId;
        if (overflowButtonRef.current === active) return OVERFLOW_BUTTON_ID;
        return focusedId;
      })();
      if (activeId !== OVERFLOW_BUTTON_ID) {
        e.preventDefault();
        handleTabSelect(activeId);
      }
    }
  }, [focusedId, visibleTabs, hasOverflow, handleTabSelect]);

  const renderTab = (tabId: string, shouldHide: boolean, posinset: number, setsize: number) => {
    const isSelected = selectedTab === tabId;
    const isFocused = !shouldHide && focusedId === tabId;
    const tabItem = tabItems.find(t => t.id === tabId)!;

    return (
      <div key={tabId} className="fx-tabbar-item" style={shouldHide ? { display: 'none' } : undefined}>
        <button
          ref={el => {
            if (el) {
              tabRefs.current.set(tabId, el);
            } else {
              tabRefs.current.delete(tabId);
            }
          }}
          role="tab"
          aria-selected={isSelected}
          aria-posinset={posinset}
          aria-setsize={setsize}
          tabIndex={isFocused ? 0 : -1}
          data-tab-id={tabId}
          onClick={() => {
            setFocusedId(tabId);
            handleTabSelect(tabId);
          }}
          onFocus={() => setFocusedId(tabId)}
          aria-hidden={shouldHide ? true : undefined}
          className={`relative z-10 flex h-full items-center p-2 cursor-pointer bg-transparent border-0 border-b-2 transition-colors ${
            isSelected
              ? 'border-sapphire-text-accent border-solid'
              : 'border-transparent hover:border-sapphire-text-accent/30'
          }`}
        >
          <span
            data-text={tabItem.label}
            className={`text-sm text-center whitespace-nowrap after:content-[attr(data-text)] after:font-semibold after:block after:h-0 after:overflow-hidden after:invisible ${
              isSelected ? 'font-semibold text-sapphire-text-accent' : 'font-normal text-foreground'
            }`}
          >
            {tabItem.label}
          </span>
        </button>
      </div>
    );
  };

  return (
    <div className={className || 'relative flex flex-col h-12'}>
      {!noUnderline && <div className="absolute bottom-0 left-0 right-0 h-px bg-border" />}
      <div className="flex flex-1 min-h-0 min-w-0 w-full items-stretch">
        <div
          ref={tabListRef}
          role="tablist"
          aria-label={accessibleName}
          onKeyDown={handleKeyDown}
          onKeyUp={handleKeyUp}
          className="flex gap-4 h-full items-stretch flex-1 min-w-0 overflow-hidden"
        >
          {tabItems.map((tab, index) => {
            const shouldHide = enableOverflow && isReady && !visibleTabIds.includes(tab.id);
            const visibleIndex = visibleTabs.findIndex(t => t.id === tab.id);
            const posinset = shouldHide ? index + 1 : visibleIndex + 1;
            const setsize = (enableOverflow && isReady) ? visibleTabs.length : tabItems.length;
            return renderTab(tab.id, shouldHide, posinset, setsize);
          })}
        </div>

        {enableOverflow && isReady && hasOverflow && (
          <TabbarOverflowButton
            ref={overflowButtonRef}
            tabs={overflowTabIds.map(id => {
              const tab = tabItems.find(t => t.id === id)!;
              return { id, label: tab.label };
            })}
            selectedTabId={selectedTab}
            onSelect={(tabId) => handleTabSelect(tabId)}
            isFocused={focusedId === OVERFLOW_BUTTON_ID}
            onFocus={() => setFocusedId(OVERFLOW_BUTTON_ID)}
            overflowId={OVERFLOW_BUTTON_ID}
            onKeyDown={handleKeyDown}
          />
        )}
      </div>
    </div>
  );
};
